function solve(grid, k) {
  const m = grid.length;
  const n = grid[0].length;

  // Precompute teleport lists
  const teleport = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => []));
  for (let i = 0; i < m; i++) {
    for (let j = 0; j < n; j++) {
      const val = grid[i][j];
      for (let x = 0; x < m; x++) {
        for (let y = 0; y < n; y++) {
          if (grid[x][y] <= val) {
            teleport[i][j].push([x, y]);
          }
        }
      }
    }
  }

  // Dijkstra's setup
  const dist = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(k+1).fill(Infinity)));
  dist[0][0][0] = 0;

  // Priority queue: [cost, i, j, t]
  const heap = [[0, 0, 0, 0]];

  // Directions for regular moves: right and down
  const dirs = [[0, 1], [1, 0]];

  function push(heap, value) {
    heap.push(value);
    let i = heap.length - 1;
    while (i > 0) {
      let parent = Math.floor((i - 1) / 2);
      if (heap[i][0] < heap[parent][0]) {
        [heap[i], heap[parent]] = [heap[parent], heap[i]];
        i = parent;
      } else {
        break;
      }
    }
  }

  function pop(heap) {
    if (heap.length === 0) return null;
    const val = heap[0];
    heap[0] = heap[heap.length - 1];
    heap.pop();
    let i = 0;
    while (i < heap.length) {
      let left = 2 * i + 1;
      let right = 2 * i + 2;
      let smallest = i;
      if (left < heap.length && heap[left][0] < heap[smallest][0]) {
        smallest = left;
      }
      if (right < heap.length && heap[right][0] < heap[smallest][0]) {
        smallest = right;
      }
      if (smallest !== i) {
        [heap[i], heap[smallest]] = [heap[smallest], heap[i]];
        i = smallest;
      } else {
        break;
      }
    }
    return val;
  }

  while (heap.length > 0) {
    const [cost, i, j, t] = pop(heap);

    // Check if we reached the destination
    if (i === m - 1 && j === n - 1) {
      return cost;
    }

    // If current cost is higher than the stored distance, skip
    if (cost > dist[i][j][t]) {
      continue;
    }

    // Process regular moves
    for (const [dx, dy] of dirs) {
      const ni = i + dx;
      const nj = j + dy;
      if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
        const new_cost = cost + grid[ni][nj];
        if (new_cost < dist[ni][nj][t]) {
          dist[ni][nj][t] = new_cost;
          push(heap, [new_cost, ni, nj, t]);
        }
      }
    }

    // Process teleport moves
    if (t < k) {
      for (const [x, y] of teleport[i][j]) {
        const new_t = t + 1;
        if (cost < dist[x][y][new_t]) {
          dist[x][y][new_t] = cost;
          push(heap, [cost, x, y, new_t]);
        }
      }
    }
  }

  // If no path found (should not happen as per problem constraints)
  return -1;
}
