class PriorityQueue {
    constructor() {
        this.heap = [];
    }
    enqueue(value) {
        this.heap.push(value);
        this.heap.sort((a, b) => a[0] - b[0]);
    }
    dequeue() {
        return this.heap.shift();
    }
    isEmpty() {
        return this.heap.length === 0;
    }
}

function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const teleportMap = Array(m).fill().map(() => Array(n).fill().map(() => []));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const val = grid[i][j];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= val) {
                        teleportMap[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    const dist = Array(m).fill().map(() => Array(n).fill().map(() => Array(k + 1).fill(Infinity)));
    dist[0][0][0] = 0;

    const pq = new PriorityQueue();
    pq.enqueue([0, 0, 0, 0]);

    while (!pq.isEmpty()) {
        const [cost, row, col, t] = pq.dequeue();
        if (row === m - 1 && col === n - 1) {
            return cost;
        }
        if (cost > dist[row][col][t]) {
            continue;
        }

        // Move right
        if (col + 1 < n) {
            const newCost = cost + grid[row][col + 1];
            if (newCost < dist[row][col + 1][t]) {
                dist[row][col + 1][t] = newCost;
                pq.enqueue([newCost, row, col + 1, t]);
            }
        }

        // Move down
        if (row + 1 < m) {
            const newCost = cost + grid[row + 1][col];
            if (newCost < dist[row + 1][col][t]) {
                dist[row + 1][col][t] = newCost;
                pq.enqueue([newCost, row + 1, col, t]);
            }
        }

        // Teleport
        for (const [x, y] of teleportMap[row][col]) {
            if (t + 1 <= k) {
                const newT = t + 1;
                if (cost < dist[x][y][newT]) {
                    dist[x][y][newT] = cost;
                    pq.enqueue([cost, x, y, newT]);
                }
            }
        }
    }

    return -1;
}
