function solve(grid, k) {
  class PriorityQueue {
    constructor() {
      this.heap = [];
    }

    push(value) {
      this.heap.push(value);
      this.heapifyUp(this.heap.length - 1);
    }

    pop() {
      if (this.heap.length === 0) return null;
      const min = this.heap[0];
      this.heap[0] = this.heap.pop();
      this.heapifyDown(0);
      return min;
    }

    heapifyUp(index) {
      while (index > 0) {
        const parentIndex = Math.floor((index - 1) / 2);
        if (this.heap[parentIndex] <= this.heap[index]) break;
        [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
        index = parentIndex;
      }
    }

    heapifyDown(index) {
      const length = this.heap.length;
      while (index < length) {
        const left = 2 * index + 1;
        const right = 2 * index + 2;
        let smallest = index;
        if (left < length && this.heap[left] < this.heap[smallest]) smallest = left;
        if (right < length && this.heap[right] < this.heap[smallest]) smallest = right;
        if (smallest !== index) {
          [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
          index = smallest;
        } else {
          break;
        }
      }
    }

    getSize() {
      return this.heap.length;
    }
  }

  const m = grid.length;
  const n = grid[0].length;

  const teleportList = new Array(m);
  for (let i = 0; i < m; i++) {
    teleportList[i] = new Array(n);
    for (let j = 0; j < n; j++) {
      teleportList[i][j] = [];
      const currentVal = grid[i][j];
      for (let x = 0; x < m; x++) {
        for (let y = 0; y < n; y++) {
          if (grid[x][y] <= currentVal) {
            teleportList[i][j].push([x, y]);
          }
        }
      }
    }
  }

  const dist = new Array(m);
  for (let i = 0; i < m; i++) {
    dist[i] = new Array(n);
    for (let j = 0; j < n; j++) {
      dist[i][j] = new Array(k + 1).fill(Infinity);
    }
  }

  dist[0][0][0] = 0;

  const pq = new PriorityQueue();
  pq.push([0, 0, 0, 0]);

  const dirs = [[0, 1], [1, 0]];

  while (pq.getSize() > 0) {
    const [cost, i, j, t] = pq.pop();

    if (cost > dist[i][j][t]) continue;

    if (i === m - 1 && j === n - 1) {
      return cost;
    }

    for (const [dx, dy] of dirs) {
      const ni = i + dx;
      const nj = j + dy;
      if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
        const newCost = cost + grid[ni][nj];
        if (newCost < dist[ni][nj][t]) {
          dist[ni][nj][t] = newCost;
          pq.push([newCost, ni, nj, t]);
        }
      }
    }

    if (t < k) {
      for (const [x, y] of teleportList[i][j]) {
        const newT = t + 1;
        if (cost < dist[x][y][newT]) {
          dist[x][y][newT] = cost;
          pq.push([cost, x, y, newT]);
        }
      }
    }
  }

  return -1;
}
