            for (const [x, y] of preTeleport[i][j]) {
                const newT = t + 1;
                if (cost < dist[x][y][newT]) {
                    dist[x][y][newT] = cost;
                    pq.push([cost, x, y, newT]);
                }
            }
        }
    }
    // If not found, return the minimum among all possible t for destination
    let minCost = Infinity;
    for (let t = 0; t <= k; t++) {
